#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_fp16.h>
#include <cuda_runtime.h>

// CUDA kernel declaration
__global__ void gemm_n2048_k4096_kernel(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int m,
    int n,
    int k
);

// Host function declaration
void run_gemm(
    const half* A,
    const half* B,
    half* C,
    int m,
    int n,
    int k,
    cudaStream_t stream
);

#endif // KERNEL_H

#include "kernel.h"
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

// Optimized for A800 (Ampere architecture, compute capability 8.0)
// Fixed dimensions: N=2048, K=4096

// Tile sizes optimized for A800 Tensor Cores and shared memory
constexpr int TILE_M = 16;
constexpr int TILE_N = 16;
constexpr int TILE_K = 16;

// Shared memory arrays for tiling
__shared__ half shared_A[16][16];
__shared__ half shared_B[16][16];

__global__ void gemm_n2048_k4096_kernel(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int m,
    int n,
    int k
) {
    // Thread indices within block
    int tid_x = threadIdx.x;
    int tid_y = threadIdx.y;

    // Block indices
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Output tile coordinates
    int row = by * TILE_M + tid_y;
    int col = bx * TILE_N + tid_x;

    // Accumulator for result (using float for precision)
    float acc = 0.0f;

    // Iterate over K dimension in tiles
    for (int tile = 0; tile < k / TILE_K; ++tile) {
        // Load A tile into shared memory
        // A is [M, K], we load A[row, tile*TILE_K + tid_x]
        int k_idx_a = tile * TILE_K + tid_x;
        if (row < m && k_idx_a < k) {
            shared_A[tid_y][tid_x] = A[row * k + k_idx_a];
        } else {
            shared_A[tid_y][tid_x] = __float2half(0.0f);
        }

        // Load B tile into shared memory
        // B is [N, K], we need B[col, tile*TILE_K + tid_y] for C[row, col]
        int k_idx_b = tile * TILE_K + tid_y;
        if (col < n && k_idx_b < k) {
            shared_B[tid_y][tid_x] = B[col * k + k_idx_b];
        } else {
            shared_B[tid_y][tid_x] = __float2half(0.0f);
        }

        // Synchronize to ensure all data is loaded
        __syncthreads();

        // Perform matrix multiplication
        // C[row, col] = sum_k A[row, k] * B[col, k]
        for (int i = 0; i < TILE_K; ++i) {
            float a_val = __half2float(shared_A[tid_y][i]);
            float b_val = __half2float(shared_B[i][tid_x]);
            acc += a_val * b_val;
        }

        __syncthreads();
    }

    // Write result back to global memory
    if (row < m && col < n) {
        C[row * n + col] = __float2half(acc);
    }
}

void run_gemm(
    const half* A,
    const half* B,
    half* C,
    int m,
    int n,
    int k,
    cudaStream_t stream
) {
    // Fixed dimensions for this kernel
    const int FIXED_N = 2048;
    const int FIXED_K = 4096;

    // Validate dimensions
    if (n != FIXED_N || k != FIXED_K) {
        // This kernel is optimized for N=2048, K=4096
        return;
    }

    // Block and grid configuration optimized for A800
    dim3 block_dim(16, 16, 1);
    dim3 grid_dim((n + TILE_N - 1) / TILE_N, 
                  (m + TILE_M - 1) / TILE_M, 
                  1);

    // Launch kernel
    gemm_n2048_k4096_kernel<<<grid_dim, block_dim, 0, stream>>>(
        A, B, C, m, n, k
    );
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <stdexcept>
#include <string>
#include "kernel.h"

// Helper function to check CUDA errors
inline void check_cuda_error(cudaError_t error, const char* operation) {
    if (error != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error in ") + operation + ": " + 
                                cudaGetErrorString(error));
    }
}

// Main run function for PyTorch extension
torch::Tensor run(torch::Tensor A, torch::Tensor B, torch::Tensor C) {
    // Validate input tensors are on CUDA
    if (!A.device().is_cuda()) {
        throw std::runtime_error("Input tensor A must be on CUDA device");
    }
    if (!B.device().is_cuda()) {
        throw std::runtime_error("Input tensor B must be on CUDA device");
    }
    if (!C.device().is_cuda()) {
        throw std::runtime_error("Output tensor C must be on CUDA device");
    }

    // Validate data types (must be float16)
    if (A.dtype() != torch::kHalf) {
        throw std::runtime_error("Input tensor A must be float16 (half) dtype");
    }
    if (B.dtype() != torch::kHalf) {
        throw std::runtime_error("Input tensor B must be float16 (half) dtype");
    }
    if (C.dtype() != torch::kHalf) {
        throw std::runtime_error("Output tensor C must be float16 (half) dtype");
    }

    // Get tensor dimensions
    int64_t m = A.size(0);
    int64_t k = A.size(1);
    int64_t n = B.size(0);
    int64_t k_b = B.size(1);

    // Validate dimensions
    if (k != k_b) {
        throw std::runtime_error("Inner dimensions must match: A[1] != B[1]");
    }

    // Check if dimensions match our optimized kernel
    if (n != 2048 || k != 4096) {
        throw std::runtime_error("This kernel is optimized for N=2048, K=4096. "
                                "Current dimensions: N=" + std::to_string(n) + 
                                ", K=" + std::to_string(k));
    }

    // Validate output tensor shape
    if (C.size(0) != m || C.size(1) != n) {
        throw std::runtime_error("Output tensor C shape mismatch. Expected: [" + 
                                std::to_string(m) + ", " + std::to_string(n) + 
                                "], Got: [" + std::to_string(C.size(0)) + ", " + 
                                std::to_string(C.size(1)) + "]");
    }

    // Get raw pointers using data_ptr with explicit type cast
    const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr());
    const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr());
    half* C_ptr = reinterpret_cast<half*>(C.data_ptr());

    // Get current CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    run_gemm(A_ptr, B_ptr, C_ptr, static_cast<int>(m), static_cast<int>(n), static_cast<int>(k), stream);

    // Check for errors
    check_cuda_error(cudaGetLastError(), "kernel launch");

    return C;
}

// PyBind11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "CUDA GEMM kernel optimized for A800 GPU";
    m.def("run", &run, "Execute GEMM operation with A @ B.T");
}
